#!/usr/bin/env python3
"""PreToolUse guard — blocks direct crud imports added to route/api files.

Modeled on anthropics/claude-code plugins/security-guidance/hooks/security_reminder_hook.py.
Exit 2 = block; exit 0 = allow.
"""
import json
import re
import sys

_ROUTE_MARKERS = ("/api/", "/routes.py", "/routers/", "_router.py")
_CRUD_RE = re.compile(r"from\s+\S*\.crud[\s.]|import\s+\S*\.crud\b")
_SEEN_FILE = "/tmp/.fastapi_layer_check_warned"


def _already_warned(path: str) -> bool:
    try:
        with open(_SEEN_FILE) as f:
            return path in f.read()
    except FileNotFoundError:
        return False


def _mark_warned(path: str) -> None:
    with open(_SEEN_FILE, "a") as f:
        f.write(path + "\n")


def main() -> None:
    try:
        payload = json.load(sys.stdin)
    except Exception:
        sys.exit(0)

    if payload.get("tool_name") not in ("Edit", "Write"):
        sys.exit(0)

    tool_input = payload.get("tool_input", {})
    file_path = tool_input.get("file_path", "")

    if not any(m in file_path for m in _ROUTE_MARKERS):
        sys.exit(0)

    content = tool_input.get("new_string", "") or tool_input.get("content", "")
    match = _CRUD_RE.search(content)
    if not match:
        sys.exit(0)

    if _already_warned(file_path):
        sys.exit(0)

    _mark_warned(file_path)
    print(
        f"[FastAPI layer guard] Direct crud import in route layer: '{match.group()}'\n"
        f"  Routes call service/ only — never import crud/ in api/ layer.\n"
        f"  See ~/.claude/rules/python-fastapi.md",
        file=sys.stderr,
    )
    sys.exit(2)


if __name__ == "__main__":
    main()

